// Run this once: node install-cert-assets.js
const fs = require('fs');
const path = require('path');

const dest = path.join(__dirname, 'uploads', 'signatures');
if (!fs.existsSync(dest)) fs.mkdirSync(dest, { recursive: true });

// President.png
fs.writeFileSync(path.join(dest, 'President.png'), Buffer.from('', 'base64'));
console.log('Written: President.png');

// secretary.png
fs.writeFileSync(path.join(dest, 'secretary.png'), Buffer.from('', 'base64'));
console.log('Written: secretary.png');

// logo.png
fs.writeFileSync(path.join(dest, 'logo.png'), Buffer.from('', 'base64'));
console.log('Written: logo.png');

// chakra.png
fs.writeFileSync(path.join(dest, 'chakra.png'), Buffer.from('', 'base64'));
console.log('Written: chakra.png');

console.log('✅ All certificate assets installed!');